#include <stdio.h>

int countSubarraysXOR(int A[], int n, int B) {
    int count = 0;
    for (int i = 0; i < n; i++) {
        int xorVal = 0;
        for (int j = i; j < n; j++) {
            xorVal ^= A[j];
            if (xorVal == B) {
                count++;
            }
        }
    }
    return count;
}

int main() {
    int A[] = {4, 2, 2, 6, 4};
    int n = sizeof(A) / sizeof(A[0]);
    int B = 6;
    printf("%d\n", countSubarraysXOR(A, n, B));
    return 0;
}

